const body = $json.body || $json;
const lead = body.lead || {};
const score = Number(body.score ?? 0);
const hot = Boolean(body.hot) || score >= 60;
const name = lead.name || 'Unknown';
const email = lead.email || '';
const biz = lead.businessType || '';
const url = lead.currentUrl || '';
const frustration = lead.frustration || '';
const source = lead.source || '';
const utm = [lead.utm_source, lead.utm_medium, lead.utm_campaign].filter(Boolean).join(' / ');
const subject = (hot ? 'HOT lead' : 'New lead') + ` · ${name} (${biz})`;
const text = [
  subject,
  '',
  `Score: ${score}/100`,
  `Email: ${email}`,
  url ? `Site: ${url}` : 'Site: (none given)',
  `Source: ${source}${utm ? ' · UTM ' + utm : ''}`,
  '',
  'Frustration:',
  frustration,
  '',
  'Suggested reply:',
  body.replyHint || '',
  '',
  `Id: ${body.id || ''}`,
].join('\n');
return [{
  json: {
    ...body,
    lead,
    hot,
    score,
    subject,
    text,
    mailto: email,
    firstName: String(name).split(/\s+/)[0] || name,
  }
}];

const j = $json;
const name = j.lead?.name || j.firstName || 'the lead';
const email = j.lead?.email || j.mailto || '';
return [{
  json: {
    ...j,
    reminderSubject: `Follow-up check · ${name}`,
    reminderText: [
      `Did you reply to ${name} (${email})?`,
      '',
      j.lead?.currentUrl ? `Their site: ${j.lead.currentUrl}` : '',
      `Original score: ${j.score}`,
      '',
      'If yes — archive. If no — send the suggested reply from the first alert.',
    ].filter(Boolean).join('\n'),
  }
}];
